import { Observable } from 'rxjs';

const observable = new Observable(observer => {
  observer.next('Hello');
  observer.next('World');
  observer.complete();
});

observable.subscribe({
  next: (value) => console.log(value),
  error: (err) => console.error(err),
  complete: () => console.log('Done')
});

import { of } from 'rxjs';
import { map } from 'rxjs/operators';

of(1, 2, 3)
  .pipe(
    map(x => x * 2),
    map(x => x + 10)
  )
  .subscribe(result => console.log(result)); // 12, 14, 16

import { fromEvent } from 'rxjs';
import { debounceTime, map, distinctUntilChanged } from 'rxjs/operators';

const searchInput = document.getElementById('search');
const searchStream = fromEvent<InputEvent>(searchInput, 'input')
  .pipe(
    debounceTime(300), // Wait 300ms after user stops typing
    map(event => (event.target as HTMLInputElement).value),
    distinctUntilChanged() // Only emit if value changed
  )
  .subscribe(query => console.log('Search:', query));

import { BehaviorSubject } from 'rxjs';

const counter = new BehaviorSubject<number>(0);

// New subscriber gets the current value immediately
counter.subscribe(value => console.log('Count:', value)); // Logs: Count: 0

counter.next(1); // Logs: Count: 1
counter.next(2); // Logs: Count: 2

// New subscriber also gets current value
counter.subscribe(value => console.log('New sub:', value)); // Logs: New sub: 2

